def options_value_iteration(n_states, terminal_states, transitions, options, gamma, theta=1e-10):
    """
    Perform SMDP value iteration using temporally extended options.
    Pure Python implementation with Gaussian elimination.
    """

    def solve_linear_system(A, b):
        """Solve Ax = b using Gaussian elimination with partial pivoting."""
        n = len(A)
        A = [row[:] for row in A]
        b = b[:]

        for i in range(n):
            max_row = max(range(i, n), key=lambda k: abs(A[k][i]))
            A[i], A[max_row] = A[max_row], A[i]
            b[i], b[max_row] = b[max_row], b[i]

            if abs(A[i][i]) > 1e-12:
                for k in range(i + 1, n):
                    factor = A[k][i] / A[i][i]
                    for j in range(i, n):
                        A[k][j] -= factor * A[i][j]
                    b[k] -= factor * b[i]

        x = [0.0] * n
        for i in range(n - 1, -1, -1):
            x[i] = b[i]
            for j in range(i + 1, n):
                x[i] -= A[i][j] * x[j]
            if abs(A[i][i]) > 1e-12:
                x[i] /= A[i][i]
        return x

    def compute_option_models(option):
        """Compute R(s,o) and F(s'|s,o) for a single option."""
        initiation = option['initiation']
        policy_dict = option['policy']
        termination = option['termination']

        R = [0.0] * n_states
        F = [[0.0] * n_states for _ in range(n_states)]

        init_states = sorted(list(initiation))
        state_idx = {s: i for i, s in enumerate(init_states)}
        n = len(init_states)

        if n == 0:
            return R, F

        A_r = [[1.0 if i == j else 0.0 for j in range(n)] for i in range(n)]
        b_r = [0.0] * n

        for i, s in enumerate(init_states):
            action = policy_dict[s]
            if s in transitions and action in transitions[s]:
                for next_s, prob, reward in transitions[s][action]:
                    beta = termination.get(next_s, 1.0)
                    b_r[i] += prob * reward

                    if next_s not in terminal_states and next_s in state_idx:
                        j = state_idx[next_s]
                        A_r[i][j] -= gamma * prob * (1 - beta)

        try:
            R_vals = solve_linear_system(A_r, b_r)
            for i, s in enumerate(init_states):
                R[s] = R_vals[i]
        except:
            pass

        for target_s in range(n_states):
            A_f = [[1.0 if i == j else 0.0 for j in range(n)] for i in range(n)]
            b_f = [0.0] * n

            for i, s in enumerate(init_states):
                action = policy_dict[s]
                if s in transitions and action in transitions[s]:
                    for next_s, prob, reward in transitions[s][action]:
                        beta = termination.get(next_s, 1.0)

                        if next_s == target_s:
                            b_f[i] += prob * beta

                        if next_s not in terminal_states and next_s in state_idx:
                            j = state_idx[next_s]
                            A_f[i][j] -= gamma * prob * (1 - beta)

            try:
                F_vals = solve_linear_system(A_f, b_f)
                for i, s in enumerate(init_states):
                    F[s][target_s] = F_vals[i]
            except:
                pass

        return R, F

    models = [compute_option_models(opt) for opt in options]

    V = [0.0] * n_states
    policy = [-1] * n_states

    for _ in range(10000):
        delta = 0.0
        V_new = [0.0] * n_states
        policy_new = [-1] * n_states

        for s in range(n_states):
            if s in terminal_states:
                V_new[s] = 0.0
                policy_new[s] = -1
                continue

            best_value = 0.0
            best_option = -1

            for opt_idx, option in enumerate(options):
                if s not in option['initiation']:
                    continue

                R, F = models[opt_idx]
                q_val = R[s] + gamma * sum(F[s][s_prime] * V[s_prime] for s_prime in range(n_states))

                if q_val > best_value:
                    best_value = q_val
                    best_option = opt_idx

            V_new[s] = best_value
            policy_new[s] = best_option
            delta = max(delta, abs(V_new[s] - V[s]))

        V = V_new
        policy = policy_new

        if delta < theta:
            break

    return [round(v, 4) for v in V]

