import numpy as np

def options_value_iteration(n_states, terminal_states, transitions, options, gamma, theta=1e-10):
    """
    Perform SMDP value iteration using temporally extended options.
    NumPy optimized version with vectorized linear algebra.
    """

    def compute_option_models(option):
        """Compute R(s,o) and F(s'|s,o) for a single option using NumPy."""
        initiation = option['initiation']
        policy_dict = option['policy']
        termination = option['termination']

        R = np.zeros(n_states)
        F = np.zeros((n_states, n_states))

        init_states = sorted(list(initiation))
        state_idx = {s: i for i, s in enumerate(init_states)}
        n_init = len(init_states)

        if n_init == 0:
            return R, F

        A_r = np.eye(n_init)
        b_r = np.zeros(n_init)

        for i, s in enumerate(init_states):
            action = policy_dict[s]
            if s in transitions and action in transitions[s]:
                for next_s, prob, reward in transitions[s][action]:
                    beta = termination.get(next_s, 1.0)
                    b_r[i] += prob * reward

                    if next_s not in terminal_states and next_s in state_idx:
                        j = state_idx[next_s]
                        A_r[i, j] -= gamma * prob * (1.0 - beta)

        try:
            R_vals = np.linalg.solve(A_r, b_r)
            for i, s in enumerate(init_states):
                R[s] = R_vals[i]
        except np.linalg.LinAlgError:
            pass

        for target_s in range(n_states):
            A_f = np.eye(n_init)
            b_f = np.zeros(n_init)

            for i, s in enumerate(init_states):
                action = policy_dict[s]
                if s in transitions and action in transitions[s]:
                    for next_s, prob, reward in transitions[s][action]:
                        beta = termination.get(next_s, 1.0)

                        if next_s == target_s:
                            b_f[i] += prob * beta

                        if next_s not in terminal_states and next_s in state_idx:
                            j = state_idx[next_s]
                            A_f[i, j] -= gamma * prob * (1.0 - beta)

            try:
                F_vals = np.linalg.solve(A_f, b_f)
                for i, s in enumerate(init_states):
                    F[s, target_s] = F_vals[i]
            except np.linalg.LinAlgError:
                pass

        return R, F

    models = [compute_option_models(opt) for opt in options]

    V = np.zeros(n_states)
    policy = np.full(n_states, -1, dtype=int)

    for _ in range(10000):
        delta = 0.0
        V_new = np.zeros(n_states)
        policy_new = np.full(n_states, -1, dtype=int)

        for s in range(n_states):
            if s in terminal_states:
                V_new[s] = 0.0
                continue

            best_value = 0.0
            best_option = -1

            for opt_idx, option in enumerate(options):
                if s not in option['initiation']:
                    continue

                R, F = models[opt_idx]
                q_val = R[s] + gamma * np.dot(F[s], V)

                if q_val > best_value:
                    best_value = q_val
                    best_option = opt_idx

            V_new[s] = best_value
            policy_new[s] = best_option
            delta = max(delta, abs(V_new[s] - V[s]))

        V = V_new
        policy = policy_new

        if delta < theta:
            break

    return [round(float(v), 4) for v in V]
